// ============================================
// ANALIZAR PARES - VERSIÓN CORREGIDA Y OPTIMIZADA v2.0
// ============================================
// CORRECCIONES:
// 1. Usa EXCLUSIVAMENTE globalRates para precios (fuente de verdad)
// 2. Validación de rangos por símbolo con fallback seguro
// 3. Logging detallado de origen de precios
// 4. Corrección de best_score y best_pair
// ============================================

const allItems = $input.all();
console.log(`📊 Recibidos ${allItems.length} items para analizar`);

// ============================================
// ESTRUCTURAS DE DATOS
// ============================================
const pairsAnalysis = {};
let bestPair = null;
let bestScore = 0; // Inicializar en 0, no -1

// Datos globales
let globalAccountData = {};
let globalNews = [];
let globalCalendar = [];
let globalPositions = [];
let globalPendingOrders = [];
let currencyStrength = null;
let globalRates = null;

// ============================================
// PRECIOS POR DEFECTO ACTUALIZADOS Y VALIDADOS
// ============================================
const DEFAULT_PRICES = {
    EURUSD: 1.1689,
    GBPUSD: 1.3570,
    USDJPY: 159.88,
    USDCHF: 0.7996
};

// RANGOS VÁLIDOS POR SÍMBOLO (para validación)
const VALID_RANGES = {
    EURUSD: { min: 1.05, max: 1.20 },
    GBPUSD: { min: 1.25, max: 1.40 },
    USDJPY: { min: 140.0, max: 170.0 },
    USDCHF: { min: 0.85, max: 1.00 }
};

// ============================================
// FUNCIÓN: Validar precio contra rango esperado
// ============================================
function validatePrice(symbol, price, source) {
    if (price === null || price === undefined || isNaN(price)) {
        console.log(`   ⚠️ ${symbol}: Precio inválido (${price}) de ${source}, usando default`);
        return { valid: false, price: DEFAULT_PRICES[symbol] };
    }

    const range = VALID_RANGES[symbol];
    if (price < range.min || price > range.max) {
        console.log(`   ⚠️ ${symbol}: Precio ${price} FUERA DE RANGO [${range.min}-${range.max}] desde ${source}, usando default`);
        return { valid: false, price: DEFAULT_PRICES[symbol] };
    }

    console.log(`   ✅ ${symbol}: Precio ${price} válido desde ${source}`);
    return { valid: true, price: price };
}

// ============================================
// PROCESAR ITEMS ENTRANTES
// ============================================
for (const item of allItems) {
    const data = item.json;

    // Extraer noticias globales
    if (data.news && Array.isArray(data.news) && data.news.length > 0) {
        globalNews = data.news;
        console.log(`📰 Noticias: ${globalNews.length} items`);
    }

    // Extraer calendario global
    if (data.calendar && Array.isArray(data.calendar) && data.calendar.length > 0) {
        globalCalendar = data.calendar;
        console.log(`📅 Calendario: ${globalCalendar.length} eventos`);
    }

    // Extraer datos de cuenta
    if (data.balance !== undefined && Object.keys(globalAccountData).length === 0) {
        globalAccountData = {
            balance: data.balance,
            equity: data.equity,
            profit: data.profit,
            free_margin: data.free_margin,
            leverage: data.leverage,
            currency: data.currency
        };
        console.log(`💰 Cuenta: balance ${data.balance}`);
    }

    // Extraer posiciones
    if (Array.isArray(data) && data.length > 0 && data[0]?.symbol !== undefined) {
        globalPositions = data;
    }
    if (data.positions && Array.isArray(data.positions)) {
        globalPositions = data.positions;
    }

    // Extraer órdenes pendientes
    if (Array.isArray(data) && data.length > 0 && data[0]?.state === "PLACED") {
        globalPendingOrders = data;
    }
    if (data.pendings && Array.isArray(data.pendings)) {
        globalPendingOrders = data.pendings;
    }
    if (data.id && data.state === "PLACED" && !Array.isArray(data)) {
        globalPendingOrders.push(data);
    }

    // EXTRAER RATES CON PRECIOS REALES (FUENTE DE VERDAD)
    if (data.rates && data.strength && data.sentiment) {
        currencyStrength = {
            rates: data.rates,
            strength: data.strength,
            sentiment: data.sentiment,
            timestamp: data.timestamp
        };
        globalRates = data.rates;
        console.log(`💹 Fortaleza de divisas cargada con precios reales`);
    }

    // EXTRAER PRECIOS DIRECTOS DE CADA DATA FETCHER (bid/ask por símbolo)
    if (data.symbol && (data.bid !== undefined || data.ask !== undefined)) {
        const sym = data.symbol;
        const price = data.bid || data.ask;

        if (!globalRates) globalRates = {};

        const validation = validatePrice(sym, price, `bid/ask directo (${sym})`);
        if (validation.valid) {
            globalRates[sym] = validation.price;
            console.log(`💵 ${sym}: Precio actualizado a ${validation.price} desde data fetcher`);
        }
    }
}

// ============================================
// ASEGURAR PRECIOS PARA TODOS LOS PARES
// ============================================
if (!globalRates) {
    console.log("⚠️ No se encontraron rates, usando valores por defecto");
    globalRates = { ...DEFAULT_PRICES };
} else {
    // Validar y completar cada par
    for (const [symbol, defaultPrice] of Object.entries(DEFAULT_PRICES)) {
        if (!globalRates[symbol]) {
            console.log(`⚠️ ${symbol}: No encontrado en rates, usando default ${defaultPrice}`);
            globalRates[symbol] = defaultPrice;
        } else {
            const validation = validatePrice(symbol, globalRates[symbol], 'rates existente');
            if (!validation.valid) {
                globalRates[symbol] = validation.price;
            }
        }
    }
}

console.log("\n💰 PRECIOS REALES CONFIRMADOS (fuente de verdad):");
for (const [symbol, price] of Object.entries(globalRates)) {
    if (DEFAULT_PRICES[symbol] !== undefined) {
        console.log(`   ${symbol}: ${price}`);
    }
}

// ============================================
// FUNCIONES DE ANÁLISIS TÉCNICO
// ============================================
function calculateRSI(candles, period = 14) {
    if (!candles || candles.length < period + 1) return 50;
    try {
        let gains = 0, losses = 0;
        for (let i = candles.length - period; i < candles.length; i++) {
            if (i === 0) continue;
            const change = (candles[i].close || 0) - (candles[i-1].close || 0);
            if (change >= 0) gains += change;
            else losses -= change;
        }
        if (losses === 0) return 100;
        const rs = gains / losses;
        return Number((100 - (100 / (1 + rs))).toFixed(2));
    } catch (error) { return 50; }
}

function determineTrend(candles) {
    if (!candles || candles.length < 20) return "neutral";
    try {
        const closes20 = candles.slice(-20).map(c => c.close || 0);
        const sma20 = closes20.reduce((a, b) => a + b, 0) / 20;
        const closes50 = candles.slice(-50).map(c => c.close || 0);
        const sma50 = closes50.reduce((a, b) => a + b, 0) / 50;
        if (sma20 > sma50 * 1.002) return "bullish";
        if (sma20 < sma50 * 0.998) return "bearish";
        return "neutral";
    } catch (error) { return "neutral"; }
}

function findSupportResistance(candles, currentPrice) {
    if (!candles || candles.length === 0) {
        return { support: currentPrice * 0.995, resistance: currentPrice * 1.005 };
    }
    try {
        const recentCandles = candles.slice(-20);
        const highs = recentCandles.map(c => c.high || c.close || 0);
        const lows = recentCandles.map(c => c.low || c.close || 0);
        let support = Math.min(...lows);
        let resistance = Math.max(...highs);
        if (support === resistance || recentCandles.length === 1) {
            support = currentPrice * 0.995;
            resistance = currentPrice * 1.005;
        }
        return { support, resistance };
    } catch (error) {
        return { support: currentPrice * 0.995, resistance: currentPrice * 1.005 };
    }
}

// ============================================
// PROCESAR CADA PAR DE DIVISAS
// ============================================
const symbols = ["EURUSD", "GBPUSD", "USDJPY", "USDCHF"];

for (const symbol of symbols) {
    console.log(`\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━`);
    console.log(`📊 Procesando par: ${symbol}`);

    // FORZAR uso de globalRates como fuente de verdad
    let currentPrice = globalRates[symbol];
    console.log(`   ✅ Precio desde globalRates: ${currentPrice}`);

    // Buscar velas para este símbolo
    let candlesData = [];
    for (const item of allItems) {
        const data = item.json;
        if (data.symbol === symbol && data.candles && Array.isArray(data.candles)) {
            candlesData = data.candles;
            console.log(`   ✅ Velas encontradas: ${candlesData.length} candles`);
            break;
        }
    }

    if (candlesData.length === 0) {
        console.log(`   ⚠️ No se encontraron velas para ${symbol}`);
    }

    // Calcular indicadores técnicos
    const rsi = calculateRSI(candlesData);
    const trend = determineTrend(candlesData);
    const sr = findSupportResistance(candlesData, currentPrice);

    // Ajustar según fortaleza de divisas si no hay velas
    let finalRsi = rsi;
    let finalTrend = trend;

    if (candlesData.length === 0 && currencyStrength) {
        const baseCurrency = symbol.substring(0, 3);
        const quoteCurrency = symbol.substring(3, 6);
        const baseStrength = currencyStrength.strength[baseCurrency] || "neutral";
        const quoteStrength = currencyStrength.strength[quoteCurrency] || "neutral";

        if (baseStrength === "bullish" && quoteStrength === "bearish") {
            finalTrend = "bullish";
            finalRsi = 65;
        } else if (baseStrength === "bearish" && quoteStrength === "bullish") {
            finalTrend = "bearish";
            finalRsi = 35;
        }
        console.log(`   📊 Ajustado por fortaleza: ${finalTrend}, RSI: ${finalRsi}`);
    }

    // Calcular score
    let score = 50;
    if (finalRsi < 35) score += 25;
    if (finalRsi > 65) score += 25;
    if (finalTrend === "bullish") score += 20;
    if (finalTrend === "bearish") score += 20;

    let finalScore = Math.max(0, Math.min(100, score));

    // Filtrar noticias y eventos relevantes
    let relevantCurrencies = [];
    if (symbol === "EURUSD") relevantCurrencies = ["EUR", "USD"];
    else if (symbol === "GBPUSD") relevantCurrencies = ["GBP", "USD"];
    else if (symbol === "USDJPY") relevantCurrencies = ["USD", "JPY"];
    else if (symbol === "USDCHF") relevantCurrencies = ["USD", "CHF"];

    const relevantNews = globalNews.filter(news => 
        news.currency && relevantCurrencies.includes(news.currency)
    );

    const relevantEvents = globalCalendar.filter(event => 
        event.currency && relevantCurrencies.includes(event.currency)
    );

    const highImpactEvents = relevantEvents.filter(e => e.impact === "high");

    // Filtrar posiciones y pendientes del símbolo
    const symbolPositions = globalPositions.filter(p => p.symbol === symbol);
    const symbolPendingOrders = globalPendingOrders.filter(p => p.symbol === symbol);

    // Almacenar análisis
    pairsAnalysis[symbol] = {
        symbol: symbol,
        score: finalScore,
        technical: {
            current_price: currentPrice,
            rsi: finalRsi,
            trend: finalTrend,
            support: sr.support,
            resistance: sr.resistance
        },
        fundamental: {
            news_count: relevantNews.length,
            high_impact_events: highImpactEvents.length,
            events: highImpactEvents.map(e => e.event).slice(0, 3),
            relevant_news: relevantNews.slice(0, 5),
            calendar_events: relevantEvents.slice(0, 5)
        },
        positions: {
            count: symbolPositions.length,
            exposure: symbolPositions.reduce((sum, p) => sum + Math.abs(p.volume || 0), 0),
            details: symbolPositions
        },
        pending_orders: {
            count: symbolPendingOrders.length,
            exposure: symbolPendingOrders.reduce((sum, p) => sum + Math.abs(p.volume || 0), 0),
            details: symbolPendingOrders
        }
    };

    console.log(`   ✅ Score: ${finalScore} | RSI: ${finalRsi} | Trend: ${finalTrend} | Price: ${currentPrice}`);

    // Actualizar mejor par (solo si score > bestScore)
    if (finalScore > bestScore) {
        bestScore = finalScore;
        bestPair = symbol;
        console.log(`   🏆 Nuevo mejor par: ${symbol} con score ${bestScore}`);
    }
}

// Fallback: si no se encontró ningún par válido
if (!bestPair) {
    bestPair = "EURUSD";
    bestScore = 50;
    console.log("⚠️ No se encontraron pares válidos, usando EURUSD por defecto");
}

// Asegurar que bestAnalysis existe y tiene precio válido
const bestAnalysis = pairsAnalysis[bestPair];
if (!bestAnalysis || !bestAnalysis.technical?.current_price) {
    console.log(`⚠️ bestAnalysis inválido para ${bestPair}, recreando`);
    pairsAnalysis[bestPair] = {
        symbol: bestPair,
        score: bestScore,
        technical: {
            current_price: globalRates[bestPair] || DEFAULT_PRICES[bestPair],
            rsi: 50,
            trend: "neutral",
            support: 0,
            resistance: 0
        },
        fundamental: { news_count: 0, high_impact_events: 0, events: [], relevant_news: [], calendar_events: [] },
        positions: { count: 0, exposure: 0, details: [] },
        pending_orders: { count: 0, exposure: 0, details: [] }
    };
}

// ============================================
// CÁLCULO DE RIESGO
// ============================================
const accountBalance = globalAccountData.balance || 100000;
const totalPositionsExposure = globalPositions.reduce((sum, p) => sum + Math.abs(p.volume || 0), 0);
const totalPendingExposure = globalPendingOrders.reduce((sum, p) => sum + Math.abs(p.volume || 0), 0);

const riskAmount = accountBalance * 0.02;
const stopLossPips = 50;
const pipValue = 10;
let recommendedVolume = riskAmount / (stopLossPips * pipValue);
recommendedVolume = Math.min(recommendedVolume, 0.05); // MAX 0.05 lots
recommendedVolume = Math.max(recommendedVolume, 0.01);
recommendedVolume = Math.round(recommendedVolume * 100) / 100;

const finalAnalysis = pairsAnalysis[bestPair];
const promptText = `Best Pair: ${bestPair}, Score: ${bestScore}, Price: ${finalAnalysis.technical.current_price}, RSI: ${finalAnalysis.technical.rsi}`;

console.log("\n========================================");
console.log("🏆 MEJOR PAR:", bestPair);
console.log(`   Score: ${bestScore}`);
console.log(`   Precio: ${finalAnalysis.technical.current_price}`);
console.log(`   RSI: ${finalAnalysis.technical.rsi}`);
console.log(`   Tendencia: ${finalAnalysis.technical.trend}`);
console.log("========================================");

// ============================================
// RESULTADO FINAL
// ============================================
return [{
    json: {
        best_pair: bestPair,
        best_score: bestScore,
        all_pairs: pairsAnalysis,
        currency_strength: currencyStrength || {
            rates: globalRates,
            strength: { EUR: "neutral", USD: "neutral", GBP: "neutral", JPY: "neutral", CHF: "neutral" },
            sentiment: { score: 0, overall: "neutral", market_mood: "calm" }
        },
        technical: finalAnalysis.technical,
        fundamental: finalAnalysis.fundamental,
        positions: {
            count: globalPositions.length,
            exposure: totalPositionsExposure,
            details: globalPositions
        },
        pending_orders: {
            count: globalPendingOrders.length,
            exposure: totalPendingExposure,
            details: globalPendingOrders
        },
        risk: {
            account_balance: accountBalance,
            risk_amount: riskAmount,
            recommended_volume: recommendedVolume,
            current_exposure: totalPositionsExposure,
            pending_exposure: totalPendingExposure
        },
        global_news: globalNews.slice(0, 5),
        global_calendar: globalCalendar.slice(0, 5),
        prompt_text: promptText,
        timestamp: new Date().toISOString()
    }
}];

// ============================================
// MEMORY MANAGER - Versión Optimizada v2.0
// ============================================

const marketData = $input.all()[0].json;

// Inicializar estructura de memoria si no existe
if (!global.tradingMemory) {
    global.tradingMemory = {
        last_analysis: {},
        recent_decisions: [],
        trades: [],
        agent_weights: {
            technical: 0.35,
            fundamental: 0.25,
            sentiment: 0.25,
            statistical: 0.15
        },
        performance: {
            technical: { wins: 0, losses: 0, total: 0, winrate: 0, last_confidence: [] },
            fundamental: { wins: 0, losses: 0, total: 0, winrate: 0, last_confidence: [] },
            sentiment: { wins: 0, losses: 0, total: 0, winrate: 0, last_confidence: [] },
            statistical: { wins: 0, losses: 0, total: 0, winrate: 0, last_confidence: [] }
        },
        global_metrics: {
            total_trades: 0,
            winning_trades: 0,
            losing_trades: 0,
            total_pips: 0,
            avg_confidence: 0,
            sharpe_ratio: 0
        },
        preferences: {
            risk_tolerance: 0.02,
            max_positions: 3,
            max_volume: 0.05,
            min_confidence: 45
        },
        last_update: new Date().toISOString(),
        weight_history: []
    };
}

// Calcular métricas derivadas
if (global.tradingMemory.trades.length > 0) {
    const lastTrades = global.tradingMemory.trades.slice(-20);
    const wins = lastTrades.filter(t => t.order?.status === "executed" && t.result === "win").length;
    const losses = lastTrades.filter(t => t.order?.status === "executed" && t.result === "loss").length;

    if (wins + losses > 0) {
        global.tradingMemory.global_metrics.winning_trades = wins;
        global.tradingMemory.global_metrics.losing_trades = losses;
        global.tradingMemory.global_metrics.total_trades = wins + losses;
    }
}

// Ajustar umbral de confianza dinámicamente
const totalTrades = global.tradingMemory.global_metrics.total_trades;
const winrate = totalTrades > 0 ? 
    (global.tradingMemory.global_metrics.winning_trades / totalTrades) * 100 : 50;

if (winrate > 60 && global.tradingMemory.preferences.min_confidence > 40) {
    global.tradingMemory.preferences.min_confidence = Math.max(40, global.tradingMemory.preferences.min_confidence - 2);
    console.log(`📈 Winrate alto (${winrate.toFixed(1)}%), bajando umbral a ${global.tradingMemory.preferences.min_confidence}%`);
} else if (winrate < 45 && winrate > 0 && global.tradingMemory.preferences.min_confidence < 55) {
    global.tradingMemory.preferences.min_confidence = Math.min(55, global.tradingMemory.preferences.min_confidence + 2);
    console.log(`📉 Winrate bajo (${winrate.toFixed(1)}%), subiendo umbral a ${global.tradingMemory.preferences.min_confidence}%`);
}

const context = {
    timestamp: new Date().toISOString(),
    market_data: marketData,
    memory: global.tradingMemory,
    recent_decisions: global.tradingMemory.recent_decisions.slice(-10),
    recent_trades: global.tradingMemory.trades.slice(-5),
    agent_performance: global.tradingMemory.performance,
    global_metrics: global.tradingMemory.global_metrics,
    preferences: global.tradingMemory.preferences
};

console.log("📚 Memory Manager: Contexto cargado");
console.log(`   - Mejor par: ${marketData.best_pair} | Score: ${marketData.best_score}`);
console.log(`   - Trades: ${global.tradingMemory.global_metrics.total_trades} | Winrate: ${winrate.toFixed(1)}%`);

return [{ json: context }];

// ============================================
// PREPARAR ORDEN - Versión Corregida v2.0
// ============================================
// CORRECCIONES:
// 1. Retorna [] (array vacío) para duplicados, no objeto con should_execute: false
// 2. Valida precio vs símbolo antes de ejecutar
// 3. Límite de volumen reducido a 0.05 lots
// ============================================

const decision = $input.all()[0].json;

// Obtener marketData de forma segura (puede venir de Memory Manager o directamente)
let marketData = null;
try {
    if ($node["Memory Manager"] && $node["Memory Manager"].json) {
        marketData = $node["Memory Manager"].json.market_data;
    }
} catch(e) {
    console.log("⚠️ No se pudo obtener marketData de Memory Manager");
}

// Fallback: si decision tiene market_data directo
if (!marketData && decision.market_data) {
    marketData = decision.market_data;
}

// Validar HOLD/ESPERAR
if (decision.decision === "esperar" || decision.decision === "hold" || decision.decision === "wait") {
    console.log("⏸️ Decisión: ESPERAR/HOLD - No se ejecuta orden");
    return []; // Array vacío para prevenir ejecución
}

// Determinar tipo de orden
let orderType = "BUY";
if (decision.decision === "vender" || decision.decision === "sell") {
    orderType = "SELL";
}

// Obtener símbolo y precio
const symbol = marketData?.best_pair || decision.symbol || "EURUSD";

// PRECIO: Usar el precio del símbolo correcto
let entryPrice = 0;

// Primero intentar del decision (si viene del agente estratega)
if (decision.entrada?.precio) {
    entryPrice = decision.entrada.precio;
}
// Luego del market data técnico
else if (marketData?.technical?.current_price) {
    entryPrice = marketData.technical.current_price;
}
// Fallback: usar el precio del par específico desde all_pairs
else if (marketData?.all_pairs?.[symbol]?.technical?.current_price) {
    entryPrice = marketData.all_pairs[symbol].technical.current_price;
}

// Validar que el precio corresponde al símbolo
const VALID_RANGES = {
    EURUSD: { min: 1.05, max: 1.20 },
    GBPUSD: { min: 1.25, max: 1.40 },
    USDJPY: { min: 140.0, max: 170.0 },
    USDCHF: { min: 0.85, max: 1.00 }
};

const DEFAULT_PRICES = {
    EURUSD: 1.1689, GBPUSD: 1.3570, USDJPY: 159.88, USDCHF: 0.7996
};

const range = VALID_RANGES[symbol];
if (range && (entryPrice < range.min || entryPrice > range.max)) {
    console.log(`⚠️ Precio ${entryPrice} fuera de rango para ${symbol}, usando default`);
    entryPrice = DEFAULT_PRICES[symbol];
}

if (entryPrice === 0) {
    console.log(`⚠️ Precio es 0, usando default para ${symbol}`);
    entryPrice = DEFAULT_PRICES[symbol];
}

let stopLoss = decision.stop_loss?.precio || 0;
let takeProfit = decision.take_profit?.objetivo1 || 0;
let volume = decision.volumen || marketData?.risk?.recommended_volume || 0.05;

// ============================================
// VALIDAR DUPLICADOS
// ============================================
const pendingOrders = marketData?.pending_orders?.details || [];

const existingOrder = pendingOrders.find(order => 
    order.symbol === symbol && 
    Math.abs(parseFloat(order.open || 0) - entryPrice) < 0.0002
);

if (existingOrder) {
    console.log(`⚠️ ORDEN DUPLICADA DETECTADA: ${orderType} ${symbol} @ ${entryPrice}`);
    console.log(`   Orden existente ID: ${existingOrder.id}`);
    console.log(`   ✅ Retornando array vacío para prevenir ejecución`);
    return []; // IMPORTANTE: array vacío, no objeto
}

// ============================================
// CALCULAR STOP LOSS Y TAKE PROFIT
// ============================================
if (stopLoss === 0) {
    const stopPips = symbol.includes("JPY") ? 30 : 0.0030;
    stopLoss = orderType === "BUY" ? entryPrice - stopPips : entryPrice + stopPips;
}

if (takeProfit === 0) {
    const tpPips = symbol.includes("JPY") ? 50 : 0.0050;
    takeProfit = orderType === "BUY" ? entryPrice + tpPips : entryPrice - tpPips;
}

// Validar lógica de SL/TP
if (orderType === "BUY") {
    if (stopLoss >= entryPrice) stopLoss = entryPrice - (symbol.includes("JPY") ? 30 : 0.0030);
    if (takeProfit <= entryPrice) takeProfit = entryPrice + (symbol.includes("JPY") ? 50 : 0.0050);
} else {
    if (stopLoss <= entryPrice) stopLoss = entryPrice + (symbol.includes("JPY") ? 30 : 0.0030);
    if (takeProfit >= entryPrice) takeProfit = entryPrice - (symbol.includes("JPY") ? 50 : 0.0050);
}

// Limitar volumen (MAX 0.05 lots)
const MAX_VOLUME = 0.05;
const MIN_VOLUME = 0.01;
volume = Math.min(volume, MAX_VOLUME);
volume = Math.max(volume, MIN_VOLUME);
volume = Math.round(volume * 100) / 100;

// Redondear precios según el par
const decimals = symbol.includes("JPY") ? 1000 : 100000;
entryPrice = Math.round(entryPrice * decimals) / decimals;
stopLoss = Math.round(stopLoss * decimals) / decimals;
