// ============================================
// FUNCIÓN: Parsear fechas MT5
// ============================================
function parseMT5Date(dateString) {
    if (!dateString) {
        return null;
    }

    // Formato MT5: "2026.04.08 16:21:06"
    const mt5Match = String(dateString).match(/(\d{4})\.(\d{2})\.(\d{2})\s+(\d{2}):(\d{2}):(\d{2})/);
    if (mt5Match) {
        const [, year, month, day, hour, minute, second] = mt5Match;
        return new Date(parseInt(year), parseInt(month) - 1, parseInt(day), 
                       parseInt(hour), parseInt(minute), parseInt(second));
    }

    // Formato ISO: "2026-04-08T16:21:06+02:00" o "2026-04-08T16:21:06Z"
    const isoDate = new Date(dateString);
    if (!isNaN(isoDate.getTime())) {
        return isoDate;
    }

    return null;
}

// ============================================
// BUSCAR ÓRDENES PENDIENTES
// ============================================
let pendingOrders = [];

if (inputData.pending_orders?.details && Array.isArray(inputData.pending_orders.details)) {
    pendingOrders = inputData.pending_orders.details;
} else if (inputData.pending_orders && Array.isArray(inputData.pending_orders)) {
    pendingOrders = inputData.pending_orders;
} else if (Array.isArray(inputData) && inputData[0]?.id) {
    pendingOrders = inputData;
} else {
    // Buscar en cualquier propiedad que sea array de órdenes
    for (const key of Object.keys(inputData)) {
        if (Array.isArray(inputData[key]) && inputData[key][0]?.id) {
            pendingOrders = inputData[key];
            break;
        }
    }
}

console.log(`📊 Total órdenes pendientes: ${pendingOrders.length}`);

if (pendingOrders.length === 0) {
    return [{
        json: {
            ...inputData,
            pending_orders_to_cancel: [],
            _debug_cancel: { 
                total_pending: 0, 
                to_cancel: 0, 
                message: "No pending orders found",
                timestamp: new Date().toISOString()
            }
        }
    }];
}

// ============================================
// CONFIGURACIÓN DE UMBRAL (48 horas por defecto)
// ============================================
const HOURS_THRESHOLD = 48; // Hacer configurable si es necesario
const THRESHOLD_MS = HOURS_THRESHOLD * 60 * 60 * 1000;
const now = Date.now();

const ordersToCancel = [];

console.log(`\n🔍 Procesando órdenes (umbral: ${HOURS_THRESHOLD}h):\n`);

for (const order of pendingOrders) {
    console.log(`━━━ Orden ID: ${order.id} | ${order.symbol} | ${order.type} ━━━`);

    // Obtener campo de tiempo
    let timeValue = order.time || order.open_time || order.created_at || order.insert_time;

    if (!timeValue) {
        console.log(`   ❌ Sin campo de tiempo - NO se cancela`);
        continue;
    }

    const orderDate = parseMT5Date(timeValue);

    if (!orderDate) {
        console.log(`   ❌ Fecha inválida: "${timeValue}" - NO se cancela`);
        continue;
    }

    const ageMs = now - orderDate.getTime();
    const ageHours = ageMs / (60 * 60 * 1000);
    const ageDays = ageHours / 24;

    console.log(`   📅 Edad: ${ageHours.toFixed(1)}h (${ageDays.toFixed(1)} días)`);

    if (ageMs > THRESHOLD_MS) {
        console.log(`   ✅ CANCELAR (> ${HOURS_THRESHOLD}h)`);
        ordersToCancel.push({
            id: order.id,
            symbol: order.symbol,
            type: order.type,
            open: order.open || order.price,
            volume: order.volume,
            age_hours: ageHours,
            age_days: ageDays,
            order_date: orderDate.toISOString()
        });
    } else {
        const remainingHours = (THRESHOLD_MS - ageMs) / (60 * 60 * 1000);
        console.log(`   ❌ MANTENER (faltan ${remainingHours.toFixed(1)}h)`);
    }
}

console.log(`\n📋 RESULTADO: ${ordersToCancel.length}/${pendingOrders.length} órdenes a cancelar`);

return [{
    json: {
        ...inputData,
        pending_orders_to_cancel: ordersToCancel.map(o => o.id),
        _debug_cancel: {
